// generated by sprint 61-1 — macOS code signing utilities

import { type SigningIdentity, type BuildEnvironment } from "./types";

export interface CodesignResult {
  readonly signed: boolean;
  readonly identity: string;
  readonly path: string;
  readonly errors: string[];
}

export interface CodesignVerifyResult {
  readonly valid: boolean;
  readonly path: string;
  readonly details: string;
  readonly errors: string[];
}

export function buildCodesignCommand(
  appPath: string,
  identity: SigningIdentity,
  entitlementsPath: string | null,
  deep: boolean = true
): string[] {
  const args: string[] = [
    "codesign",
    "--force",
    "--options",
    "runtime",
    "--sign",
    identity.identity,
    "--timestamp",
  ];

  if (deep) {
    args.push("--deep");
  }

  if (entitlementsPath) {
    args.push("--entitlements", entitlementsPath);
  }

  if (identity.keychainPath) {
    args.push("--keychain", identity.keychainPath);
  }

  args.push(appPath);

  return args;
}

export function buildCodesignVerifyCommand(appPath: string): string[] {
  return [
    "codesign",
    "--verify",
    "--deep",
    "--strict",
    "--verbose=2",
    appPath,
  ];
}

export function buildSpctlAssessCommand(appPath: string): string[] {
  return ["spctl", "--assess", "--type", "execute", "--verbose=2", appPath];
}

export function buildKeychainSetupCommands(
  keychainPath: string,
  keychainPassword: string,
  certBase64EnvVar: string,
  certPasswordEnvVar: string
): string[][] {
  const tempCertPath = "/tmp/build_certificate.p12";

  return [
    ["security", "create-keychain", "-p", keychainPassword, keychainPath],
    [
      "security",
      "set-keychain-settings",
      "-lut",
      "21600",
      keychainPath,
    ],
    ["security", "unlock-keychain", "-p", keychainPassword, keychainPath],
    [
      "bash",
      "-c",
      `echo "\${${certBase64EnvVar}}" | base64 --decode > ${tempCertPath}`,
    ],
    [
      "security",
      "import",
      tempCertPath,
      "-k",
      keychainPath,
      "-P",
      `\${${certPasswordEnvVar}}`,
      "-T",
      "/usr/bin/codesign",
    ],
    [
      "security",
      "set-key-partition-list",
      "-S",
      "apple-tool:,apple:",
      "-k",
      keychainPassword,
      keychainPath,
    ],
    [
      "security",
      "list-keychains",
      "-d",
      "user",
      "-s",
      keychainPath,
      "login.keychain-db",
    ],
  ];
}

export function buildKeychainCleanupCommands(
  keychainPath: string
): string[][] {
  return [
    ["security", "delete-keychain", keychainPath],
    ["rm", "-f", "/tmp/build_certificate.p12"],
  ];
}

export function resolveSigningIdentityFromEnv(): SigningIdentity | null {
  const identity =
    process.env.APPLE_SIGNING_IDENTITY ??
    process.env.CSC_NAME ??
    null;
  const teamId =
    process.env.APPLE_TEAM_ID ??
    process.env.CSC_TEAM_ID ??
    null;

  if (!identity || !teamId) {
    return null;
  }

  return {
    identity,
    teamId,
    keychainPath: process.env.KEYCHAIN_PATH ?? null,
    keychainPassword: process.env.KEYCHAIN_PASSWORD ?? null,
  };
}

export function validateBuildEnvironmentForSigning(
  env: BuildEnvironment
): string[] {
  const errors: string[] = [];

  if (!env.xcodeVersion) {
    errors.push(
      "Xcode is not detected. Code signing requires Xcode command line tools."
    );
  }

  if (env.arch !== "x86_64" && env.arch !== "aarch64") {
    errors.push(`Unsupported architecture: ${env.arch}`);
  }

  return errors;
}
